+#[test]
+fn validation_report_serde_round_trip() {
+    let report = ValidationReport {
+        generated_at: "2026-02-07T00:00:00Z".to_string(),
+        task: "test".to_string(),
+        stats: ValidationStats {
+            total_input_candidates: 10,
+            after_dedup: 8,
+            true_extension: 5,
+            mention_only: 2,
+            unknown: 1,
+            sources_merged: 3,
